class Solution:
    def reverseParentheses(self, s: str) -> str:
        stack = ['']
        for c in s:
            if c == '(':
                stack.append('')
            elif c == ')':
                last = stack.pop()[::-1]
                stack[-1] += last
            else:
                stack[-1] += c
        return stack[-1]
```
